"use client";

import { useMemo } from "react";
import { Invoice, PurchaseOrder } from "@/types";
import { formatCurrency } from "@/lib/currencies";

interface InvoiceDetailModalProps {
    invoice: Invoice;
    po?: PurchaseOrder;
    onClose: () => void;
    onPay: (id: string) => void;
}

export default function InvoiceDetailModal({
    invoice,
    po,
    onClose,
    onPay,
    onStatusUpdate
}: InvoiceDetailModalProps) {

    // 3-Way Match Logic
    const matchStatus = useMemo(() => {
        if (!po) return {
            status: 'MISSING_PO',
            match: false,
            poAmount: 0,
            invAmount: invoice.amount,
            receiptAmount: 0
        };

        const poAmount = po.totalAmount;
        const invAmount = invoice.amount;
        const receiptAmount = po.status === 'RECEIVED' ? po.totalAmount : 0; // Simulated receipt logic

        const match = Math.abs(poAmount - invAmount) < 0.01 &&
            Math.abs(receiptAmount - invAmount) < 0.01;

        return {
            status: match ? 'MATCH' : 'MISMATCH',
            match,
            poAmount,
            invAmount,
            receiptAmount
        };
    }, [invoice, po]);

    return (
        <div style={{
            position: 'fixed', inset: 0, zIndex: 50,
            backgroundColor: 'rgba(0,0,0,0.5)', backdropFilter: 'blur(4px)',
            display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '1rem'
        }}>
            <div className="card" style={{
                width: '900px', maxWidth: '95%', maxHeight: '90vh', overflowY: 'auto',
                animation: 'slideIn 0.3s ease-out'
            }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '2rem' }}>
                    <h2 style={{ fontSize: '1.5rem', fontWeight: 'bold' }}>Invoice #{invoice.invoiceNumber}</h2>
                    <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: '1.5rem', cursor: 'pointer' }}>&times;</button>
                </div>

                {/* 3-Way Match Visualizer */}
                <div style={{ marginBottom: '2rem', padding: '1.5rem', backgroundColor: '#f8fafc', borderRadius: '12px', border: '1px solid #e2e8f0' }}>
                    <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '1.5rem', textAlign: 'center' }}>3-Way Matching Validation</h3>

                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'relative' }}>

                        {/* Connecting Line */}
                        <div style={{
                            position: 'absolute', top: '40px', left: '10%', right: '10%', height: '4px',
                            backgroundColor: matchStatus.match ? '#22c55e' : '#ef4444',
                            zIndex: 0, opacity: 0.3
                        }}></div>

                        {/* PO Node */}
                        <div style={{ zIndex: 1, textAlign: 'center', width: '200px' }}>
                            <div style={{
                                width: '80px', height: '80px', margin: '0 auto 1rem', borderRadius: '50%',
                                backgroundColor: 'white', border: '3px solid #3b82f6',
                                display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '2rem'
                            }}>
                                📝
                            </div>
                            <div style={{ fontWeight: 600 }}>Purchase Order</div>
                            <div style={{ color: '#64748b', fontSize: '0.9rem' }}>{po ? formatCurrency(po.totalAmount, po.currency) : 'N/A'}</div>
                            {po && <div style={{ fontSize: '0.8rem', color: '#3b82f6' }}>#{po.poNumber}</div>}
                        </div>

                        {/* Receipt Node */}
                        <div style={{ zIndex: 1, textAlign: 'center', width: '200px' }}>
                            <div style={{
                                width: '80px', height: '80px', margin: '0 auto 1rem', borderRadius: '50%',
                                backgroundColor: 'white',
                                border: `3px solid ${matchStatus.receiptAmount > 0 ? '#22c55e' : '#f59e0b'}`,
                                display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '2rem'
                            }}>
                                📦
                            </div>
                            <div style={{ fontWeight: 600 }}>Goods Receipt</div>
                            <div style={{ color: '#64748b', fontSize: '0.9rem' }}>{matchStatus.status === 'MISSING_PO' ? 'N/A' : formatCurrency(matchStatus.receiptAmount, invoice.currency)}</div>
                            <div style={{ fontSize: '0.8rem', color: matchStatus.receiptAmount > 0 ? '#22c55e' : '#f59e0b' }}>
                                {matchStatus.receiptAmount > 0 ? 'Received' : 'Pending Receipt'}
                            </div>
                        </div>

                        {/* Invoice Node */}
                        <div style={{ zIndex: 1, textAlign: 'center', width: '200px' }}>
                            <div style={{
                                width: '80px', height: '80px', margin: '0 auto 1rem', borderRadius: '50%',
                                backgroundColor: 'white', border: '3px solid #8b5cf6',
                                display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '2rem'
                            }}>
                                🧾
                            </div>
                            <div style={{ fontWeight: 600 }}>Invoice</div>
                            <div style={{ color: '#64748b', fontSize: '0.9rem' }}>{formatCurrency(invoice.amount, invoice.currency)}</div>
                            <div style={{ fontSize: '0.8rem', color: '#8b5cf6' }}>#{invoice.invoiceNumber}</div>
                        </div>

                    </div>

                    <div style={{ textAlign: 'center', marginTop: '1.5rem' }}>
                        {matchStatus.match ? (
                            <span style={{ padding: '0.5rem 1rem', backgroundColor: '#dcfce7', color: '#166534', borderRadius: '99px', fontWeight: 600 }}>
                                ✅ 3-Way Match Successful
                            </span>
                        ) : (
                            <span style={{ padding: '0.5rem 1rem', backgroundColor: '#fee2e2', color: '#991b1b', borderRadius: '99px', fontWeight: 600 }}>
                                ⚠️ Mismatch Detected
                            </span>
                        )}
                    </div>
                </div>

                {/* Details Grid */}
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2rem' }}>

                    {/* Invoice Details */}
                    <div>
                        <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '0.75rem' }}>Invoice Details</h3>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', fontSize: '0.9rem' }}>
                            <div style={{ color: '#64748b' }}>Status:</div>
                            <div style={{ fontWeight: 500 }}>{invoice.status}</div>

                            <div style={{ color: '#64748b' }}>Vendor:</div>
                            <div style={{ fontWeight: 500 }}>{invoice.vendorName}</div>

                            <div style={{ color: '#64748b' }}>Issue Date:</div>
                            <div style={{ fontWeight: 500 }}>{invoice.issueDate instanceof Date ? invoice.issueDate.toLocaleDateString() : new Date(invoice.issueDate).toLocaleDateString()}</div>

                            <div style={{ color: '#64748b' }}>Due Date:</div>
                            <div style={{ fontWeight: 500 }}>{invoice.dueDate instanceof Date ? invoice.dueDate.toLocaleDateString() : new Date(invoice.dueDate).toLocaleDateString()}</div>
                        </div>
                    </div>

                    {/* File Upload / Attachment */}
                    <div>
                        <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '0.75rem' }}>Invoice Attachment</h3>
                        <InvoiceUpload
                            onFileSelect={(file) => {
                                console.log("File selected:", file);
                                // In a real app, you'd upload this to Firebase Storage
                                if (onStatusUpdate && file) {
                                    // Simulated attachment feedback
                                }
                            }}
                            currentFileName={invoice.fileName}
                        />
                    </div>

                </div>

                {/* Actions */}
                <div style={{ marginTop: '2rem', borderTop: '1px solid var(--border)', paddingTop: '1.5rem', display: 'flex', justifyContent: 'flex-end', gap: '1rem' }}>
                    <button onClick={onClose} className="btn" style={{ border: '1px solid var(--border)' }}>Close</button>

                    {invoice.status === 'PENDING' && onStatusUpdate && (
                        <>
                            <button
                                onClick={() => onStatusUpdate(invoice.id!, 'REJECTED')}
                                className="btn"
                                style={{ border: '1px solid #EF4444', color: '#EF4444' }}
                            >
                                Reject Invoice
                            </button>
                            <button
                                onClick={() => onStatusUpdate(invoice.id!, 'APPROVED')}
                                className="btn btn-accent"
                                disabled={!matchStatus.match}
                                style={{ opacity: matchStatus.match ? 1 : 0.5 }}
                            >
                                Approve for Payment
                            </button>
                        </>
                    )}

                    {invoice.status === 'APPROVED' && (
                        <button
                            onClick={() => onPay(invoice.id!)}
                            className="btn btn-primary"
                            style={{ background: 'var(--success)', border: 'none' }}
                        >
                            Mark as Paid
                        </button>
                    )}
                </div>
            </div>
        </div>
    );
}
